// qTotalW = qRadW + qConvW + qLatW (różnice ±1 W vs druk = zaokrąglenia źródła).
// Urządzenia okapowe: do pomieszczenia trafia wyłącznie składowa radiacyjna.
// Tabele 6/7/10: brak pomiarowego podziału rad/conv -> qRadW/qConvW = null,
//   stosować radiantFraction (RP-1482: 0.10 z wentylatorem, 0.30 bez; domyślnie 0.30).
// name = nazwa wyświetlana (PL), nameEn = dosłowna nazwa wiersza ASHRAE (do weryfikacji ze źródłem).
// ============================================================================

export type SourceTable = '5A' | '5B' | '5C' | '5D' | '5E' | '5F' | '6' | '7' | '10';

export type ApplianceCategory =
  | 'kitchen-unhooded-idle'     // 5A
  | 'kitchen-unhooded-cooking'  // 5B
  | 'kitchen-hooded-idle'       // 5C, 5D, 5E
  | 'warewashing'               // 5F
  | 'medical'                   // 6
  | 'laboratory'                // 7
  | 'misc';                     // 10

